from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    for subject, triples in subject_map.items():
        if sentence:
            sentence += " which "
        sentence += f"{subject} "
        for i, (predicate, obj) in enumerate(triples):
            if predicate == "cityServed":
                sentence += f"serves the city of {obj}"
            elif predicate == "mayor":
                sentence += f"has a mayor named {obj}"
            elif predicate == "isPartOf":
                sentence += f"is part of {obj}"
            elif predicate == "operatingOrganisation":
                sentence += f"is operated by {obj}"
            elif predicate == "location":
                sentence += f"is located in {obj}"
            elif predicate == "elevationAboveTheSeaLevel":
                sentence += f"is {obj} metres above sea level"
            elif predicate == "runwayName":
                sentence += f"has a runway name of {obj}"
            elif predicate == "runwayLength":
                # Use the preferred format from examples
                sentence += f"has a runway length of {obj}"
            elif predicate == "country":
                sentence += f"is located in {obj}"
            elif predicate == "capital":
                sentence += f"has {obj} as its capital"
            elif predicate == "language":
                sentence += f"where {obj} is spoken"
            elif predicate == "leader":
                sentence += f"is led by {obj}"
            elif predicate == "owner":
                sentence += f"is owned by {obj}"
            elif predicate == "1stRunwayLengthFeet":
                sentence += f"has a first runway length of {obj} feet"
            elif predicate == "1stRunwaySurfaceType":
                sentence += f"has a first runway surface type of {obj}"
            elif predicate == "3rdRunwayLengthFeet":
                sentence += f"has a third runway length of {obj} feet"
            elif predicate == "icaoLocationIdentifier":
                sentence += f"has an ICAO location identifier of {obj}"
            elif predicate == "locationIdentifier":
                sentence += f"has a location identifier of {obj}"
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                sentence += f"is {obj} feet above sea level"
            elif predicate == "iataLocationIdentifier":
                sentence += f"has an IATA location identifier of {obj}"
            elif predicate == "nativeName":
                sentence += f"has a native name of {obj}"
            elif predicate == "leaderParty":
                sentence += f"has a leader party of {obj}"
            elif predicate == "demonym":
                sentence += f"whose people are called {obj}"
            elif predicate == "officialLanguage":
                sentence += f"has {obj} as its official language"
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                sentence += f"is {obj} metres above sea level"
            elif predicate == "runwayName":
                sentence += f"has a runway name of {obj}"
            else:
                # Handle other predicates with more natural phrasing
                normalized_pred = predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway').replace('Length', ' length').replace('SurfaceType', ' surface type').replace('AboveTheSeaLevel', ' above sea level').replace('LocationIdentifier', ' identifier').replace('Iata', 'IATA').replace('Icao', 'ICAO').replace('InFeet', ' in feet').replace('InMetres', ' in metres')
                if "runway" in predicate or "elevation" in predicate or "length" in predicate:
                    sentence += f"has {normalized_pred} of {obj}"
                else:
                    sentence += f"has a {normalized_pred} of {obj}"
            if i < len(triples) - 1:
                if predicate in ["cityServed", "location", "country", "elevationAboveTheSeaLevel", "elevationAboveTheSeaLevelInFeet", "elevationAboveTheSeaLevelInMetres", "demonym", "runwayName", "1stRunwaySurfaceType", "runwayLength", "1stRunwayLengthFeet", "3rdRunwayLengthFeet"]:
                    sentence += ", "
                else:
                    sentence += " and "
    return sentence + "."
